  const table = getInput("table" /* Table */, { required: true });
  const createdAt = getInput("created_at" /* CreatedAt */, { required: true });
  const startedAt = getInput("started_at" /* StartedAt */, { required: true });
  const completedAt = getInput("completed_at" /* CompletedAt */, { required: true });
  const matrixName = getInput("matrix_name" /* MatrixName */);
  const matrixValue = getInput("matrix_value" /* MatrixValue */);
  const result = getInput("result" /* Result */, { required: true });
  const draft = getInput("draft" /* Draft */);
  const jobLink = getInput("job_link" /* JobLink */);
  const triggeringActor = getInput("triggering_actor" /* TriggeringActor */);
  const runAttempt = Number(
    getInput("run_attempt" /* RunAttempt */, { required: true })
  );
  const headRef = getInput("head_ref" /* HeadRef */);
  const baseRef = getInput("base_ref" /* BaseRef */);
  const runnerType = getInput("runner_type" /* RunnerType */, { required: true });
  const runnerName = getInput("runner_name" /* RunnerName */, { required: true });
